// ════════════════════════════════════════════════════════
// PARSE NORTH STAR + MASTER TASK LIST
// Extracts rock statuses, Priority A tasks, and builds
// all data needed for the weekly digest email.
// ════════════════════════════════════════════════════════

const nsBinary = $('S3: Get North Star').first().binary;
const mtlBinary = $('S3: Get Master Task List').first().binary;

function extractText(binaryObj) {
  const key = Object.keys(binaryObj || {})[0];
  if (!key || !binaryObj[key]?.data) return '';
  return Buffer.from(binaryObj[key].data, 'base64').toString('utf-8');
}

const nsContent = extractText(nsBinary);
const mtlContent = extractText(mtlBinary);

const ROCKS = [
  { area: 'faith',      emoji: '🙏', pillar: 'Faith & Spiritual Growth',     rock: 'Launch the Social Media Bible Study',      field: 'nm-progress-faith' },
  { area: 'family',     emoji: '💒', pillar: 'Marriage & Family',             rock: 'Marriage Alignment with Christy',           field: 'nm-progress-family' },
  { area: 'business',   emoji: '🚀', pillar: 'Business & Consulting',         rock: 'Ship the MVP — Echelon Seven',             field: 'nm-progress-business' },
  { area: 'work',       emoji: '🏥', pillar: 'Career (Parallon)',             rock: 'Deliver Union Project + Position for Exit', field: 'nm-progress-work' },
  { area: 'health',     emoji: '💪', pillar: 'Health & Home',                 rock: 'Hip Decision + 3x/week Gym for 8 Weeks',   field: 'nm-progress-health' }
];

// Extract progress from North Star inline fields
function getProgress(content, field) {
  const rx = new RegExp(`\\[${field}::\\s*([\\d]+)%?\\s*\\]`, 'i');
  const m = content.match(rx);
  return m ? parseInt(m[1]) : 0;
}

const rocks = ROCKS.map(r => ({
  ...r,
  progress: getProgress(nsContent, r.field),
  status: (() => {
    const p = getProgress(nsContent, r.field);
    if (p === 0) return { label: 'Not Started', color: '#555' };
    if (p < 25) return { label: 'Just Starting', color: '#f5a623' };
    if (p < 75) return { label: 'In Progress', color: '#4ecdc4' };
    if (p < 100) return { label: 'Almost Done', color: '#667eea' };
    return { label: 'Complete! 🎉', color: '#4caf50' };
  })()
}));

// Extract open Priority A tasks from MTL
const taskRx = /^\s*- \[ \]\s+(.+)$/gm;
const areaRx = /\[area::\s*(\w+)\s*\]/;
const priorityRx = /\[priority::\s*A\s*\]/i;
const dueRx = /\[due::\s*(\d{4}-\d{2}-\d{2})\s*\]/;

const AREA_EMOJI = { faith:'🙏', family:'💒', business:'🚀', consulting:'💼', work:'🏥', health:'💪', home:'🏠', personal:'🤖' };
const today = new Date();
const todayStr = today.toISOString().split('T')[0];

const priorityATasks = [];
let taskMatch;
taskRx.lastIndex = 0;

while ((taskMatch = taskRx.exec(mtlContent)) !== null) {
  const line = taskMatch[1];
  if (!priorityRx.test(line)) continue;
  const areaMatch = line.match(areaRx);
  const dueMatch = line.match(dueRx);
  const area = areaMatch ? areaMatch[1] : 'personal';
  const cleanTitle = line.replace(/\[[^\]]+::[^\]]+\]/g, '').trim();
  const due = dueMatch ? dueMatch[1] : null;
  const isOverdue = due && new Date(due + 'T00:00:00') < today;
  priorityATasks.push({ title: cleanTitle, area, emoji: AREA_EMOJI[area] || '📌', due, isOverdue });
}

return [{ json: { rocks, priorityATasks, todayStr, nsContent: nsContent.slice(0, 200) } }];

// ════════════════════════════════════════════════════════
// BUILD WEEKLY DIGEST HTML EMAIL
// ════════════════════════════════════════════════════════
const { rocks, priorityATasks, todayStr } = $input.item.json;

function progressBar(pct, color) {
  const w = Math.min(100, Math.max(0, pct));
  return `<div style="background:#2a2a3e;border-radius:8px;height:12px;width:100%;overflow:hidden;margin:8px 0">
    <div style="width:${w}%;background:${color};height:100%;border-radius:8px;transition:width 0.3s"></div>
  </div><span style="font-size:0.8em;color:#888">${w}% complete</span>`;
}

const rockCards = rocks.map(r => `
  <div style="background:#1e1e2e;border-radius:12px;padding:20px;margin:12px 0;border-left:4px solid ${r.status.color}">
    <div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:8px">
      <h3 style="margin:0;color:#e0e0f0">${r.emoji} ${r.pillar}</h3>
      <span style="background:${r.status.color};color:#000;font-size:0.75em;padding:3px 10px;border-radius:12px;font-weight:700">${r.status.label}</span>
    </div>
    <p style="margin:0 0 8px;color:#a0a0b0;font-style:italic">&ldquo;${r.rock}&rdquo;</p>
    ${progressBar(r.progress, r.status.color)}
  </div>`).join('');

const taskRowsByArea = {};
for (const t of priorityATasks) {
  if (!taskRowsByArea[t.area]) taskRowsByArea[t.area] = [];
  taskRowsByArea[t.area].push(t);
}

const taskSection = priorityATasks.length === 0
  ? '<p style="color:#888">No open Priority A tasks. Clean slate! 🎉</p>'
  : Object.entries(taskRowsByArea).map(([area, tasks]) => `
    <h4 style="color:#a0a0b0;margin:16px 0 8px">${tasks[0].emoji} ${area.charAt(0).toUpperCase()+area.slice(1)}</h4>
    ${tasks.map(t => `
      <div style="background:#1e1e2e;border-radius:8px;padding:10px 14px;margin:6px 0;${t.isOverdue?'border-left:3px solid #ff6b6b':''}">     
        ${t.isOverdue ? '🔴 ' : ''}${t.title}${t.due ? ` <span style="color:#888;font-size:0.8em">(${t.isOverdue?'OVERDUE — ':''}${t.due})</span>` : ''}
      </div>`).join('')}`).join('');

const overallPct = Math.round(rocks.reduce((s, r) => s + r.progress, 0) / rocks.length);

const weekNumber = Math.ceil((new Date() - new Date(new Date().getFullYear(), 0, 1)) / 604800000);

const html = `<!DOCTYPE html><html><head><meta charset="utf-8"></head>
<body style="background:#13131f;color:#e0e0f0;font-family:system-ui,sans-serif;max-width:700px;margin:0 auto;padding:24px">
  <div style="background:linear-gradient(135deg,#667eea,#764ba2);border-radius:20px;padding:32px;margin-bottom:28px">
    <h1 style="margin:0;color:#fff;font-size:1.8em">📊 Weekly Needle Mover Digest</h1>
    <p style="margin:8px 0 0;color:rgba(255,255,255,0.8)">Week ${weekNumber} · ${todayStr} · Q2 2026</p>
    <div style="margin-top:16px">
      <span style="color:rgba(255,255,255,0.7)">Overall Q2 Progress:</span>
      <div style="background:rgba(255,255,255,0.2);border-radius:8px;height:16px;margin-top:6px;overflow:hidden">
        <div style="width:${overallPct}%;background:#fff;height:100%;border-radius:8px"></div>
      </div>
      <span style="color:rgba(255,255,255,0.9);font-weight:700">${overallPct}% across all 5 rocks</span>
    </div>
  </div>

  <h2 style="color:#e0e0f0;border-bottom:1px solid #2a2a3e;padding-bottom:8px">🎯 Q2 Quarterly Rocks</h2>
  ${rockCards}

  <h2 style="color:#e0e0f0;border-bottom:1px solid #2a2a3e;padding-bottom:8px;margin-top:32px">🔴 Open Priority A Tasks (${priorityATasks.length})</h2>
  ${taskSection}

  <div style="background:#1e1e2e;border-radius:12px;padding:20px;margin-top:28px">
    <h3 style="margin:0 0 12px;color:#667eea">📋 Weekly Review Prompts</h3>
    <ol style="color:#a0a0b0;margin:0;padding-left:20px">
      <li style="margin:8px 0">Which rock moved this week — and what drove it?</li>
      <li style="margin:8px 0">Which rock is stalling — and what's the one next action?</li>
      <li style="margin:8px 0">What are your Top 3 needle movers for next week?</li>
      <li style="margin:8px 0">Did you live according to your faith and values?</li>
      <li style="margin:8px 0">Is there anything to celebrate or be grateful for?</li>
    </ol>
  </div>

  <hr style="border:1px solid #2a2a3e;margin:28px 0">
  <p style="color:#444;font-size:0.8em">Sent every Sunday at 6PM CT · ObsidianHomeOrchestrator</p>
</body></html>`;

return [{
  json: {
    subject: `📊 Weekly Digest — ${overallPct}% Q2 Progress · ${priorityATasks.length} Priority A Open · ${todayStr}`,
    html
  }
}];
